import { useEffect, useState } from "react";
import { getTasksByProject, updateTaskStatus } from "../services/taskService";

function KanbanPage() {
  const [tasks, setTasks] = useState([]);
  const [draggedTaskId, setDraggedTaskId] = useState(null);

  const fetchTasks = async () => {
    try {
      const data = await getTasksByProject();
      setTasks(data);
    } catch (error) {
      console.error("Error fetching tasks:", error.message);
    }
  };

  useEffect(() => {
    fetchTasks();
  }, []);

  const todoTasks = tasks.filter((task) => task.status === "todo");
  const inProgressTasks = tasks.filter((task) => task.status === "inprogress");
  const doneTasks = tasks.filter((task) => task.status === "done");

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await updateTaskStatus(taskId, newStatus);
      fetchTasks();
    } catch (error) {
      console.error("Error updating task status:", error.message);
    }
  };

  const handleDragStart = (taskId) => {
    setDraggedTaskId(taskId);
  };

  const handleDragOver = (e) => {
    e.preventDefault();
  };

  const handleDrop = async (newStatus) => {
    if (!draggedTaskId) return;

    try {
      await updateTaskStatus(draggedTaskId, newStatus);
      setDraggedTaskId(null);
      fetchTasks();
    } catch (error) {
      console.error("Error dropping task:", error.message);
    }
  };

  const getDeadlineStatus = (deadline) => {
    if (!deadline) return null;

    const today = new Date();
    const dueDate = new Date(deadline);

    today.setHours(0, 0, 0, 0);
    dueDate.setHours(0, 0, 0, 0);

    const diffTime = dueDate - today;
    const diffDays = diffTime / (1000 * 60 * 60 * 24);

    if (diffDays < 0) {
      return "overdue";
    }

    if (diffDays <= 2) {
      return "near";
    }

    return "normal";
  };

  const renderDeadlineReminder = (task) => {
    if (task.status === "done") return null;

    const status = getDeadlineStatus(task.deadline);

    if (!status || status === "normal") return null;

    if (status === "overdue") {
      return (
        <p
          style={{
            color: "white",
            background: "#d9534f",
            padding: "8px",
            borderRadius: "5px",
            fontWeight: "bold",
            marginTop: "10px",
          }}
        >
          Deadline dépassée
        </p>
      );
    }

    if (status === "near") {
      return (
        <p
          style={{
            color: "#856404",
            background: "#fff3cd",
            padding: "8px",
            borderRadius: "5px",
            fontWeight: "bold",
            marginTop: "10px",
          }}
        >
          Deadline proche
        </p>
      );
    }

    return null;
  };

  const renderTaskCard = (task) => (
    <div
      key={task._id}
      draggable
      onDragStart={() => handleDragStart(task._id)}
      style={{
        background: "#fff",
        border: "1px solid #ddd",
        borderRadius: "8px",
        padding: "10px",
        marginBottom: "10px",
        boxShadow: "0 2px 5px rgba(0,0,0,0.08)",
        cursor: "grab",
      }}
    >
      <h4>{task.title}</h4>
      <p>{task.description}</p>

      <p>
        <strong>Priority:</strong> {task.priority}
      </p>

      <p>
        <strong>Deadline:</strong>{" "}
        {task.deadline ? task.deadline.slice(0, 10) : "No deadline"}
      </p>

      {renderDeadlineReminder(task)}

      <select
        value={task.status}
        onChange={(e) => handleStatusChange(task._id, e.target.value)}
      >
        <option value="todo">To do</option>
        <option value="inprogress">In progress</option>
        <option value="done">Done</option>
      </select>
    </div>
  );

  return (
    <div style={{ padding: "20px" }}>
      <h1>Kanban Board</h1>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr 1fr",
          gap: "20px",
          alignItems: "start",
        }}
      >
        <div
          onDragOver={handleDragOver}
          onDrop={() => handleDrop("todo")}
          style={{
            background: "#f4f4f4",
            padding: "15px",
            borderRadius: "10px",
            minHeight: "400px",
            border: "2px dashed #ccc",
          }}
        >
          <h2>To do</h2>
          {todoTasks.map(renderTaskCard)}
        </div>

        <div
          onDragOver={handleDragOver}
          onDrop={() => handleDrop("inprogress")}
          style={{
            background: "#f4f4f4",
            padding: "15px",
            borderRadius: "10px",
            minHeight: "400px",
            border: "2px dashed #ccc",
          }}
        >
          <h2>In progress</h2>
          {inProgressTasks.map(renderTaskCard)}
        </div>

        <div
          onDragOver={handleDragOver}
          onDrop={() => handleDrop("done")}
          style={{
            background: "#f4f4f4",
            padding: "15px",
            borderRadius: "10px",
            minHeight: "400px",
            border: "2px dashed #ccc",
          }}
        >
          <h2>Done</h2>
          {doneTasks.map(renderTaskCard)}
        </div>
      </div>
    </div>
  );
}

export default KanbanPage;
